    public void addPrice(String skuSuffix, String sku, BigDecimal priceBD, String parentPrice) {
        if (skuSuffix.equals("")) return;
        if (!parentPrice.matches("-?\\d+(\\.\\d+)?")) return;
        
        BigDecimal parentPriceBD = Encoder.parseBigDecimal(parentPrice);
        if (parentPriceBD.doubleValue() == 0) return;
        
        BigDecimal percentage = priceBD.divide(parentPriceBD, 2, ROUND_HALF_UP);
        
        Map<String, BigDecimal> skuToPercentage = this.skuSuffixMap.get(skuSuffix);
        if (skuToPercentage == null) {
            skuToPercentage = new HashMap<>();
            this.skuSuffixMap.put(skuSuffix, skuToPercentage);
        }
        skuToPercentage.put(sku, percentage);
    }
    
    public void addUpliftedCogs(String sku, String productType, boolean isBundle, BigDecimal price, BigDecimal upliftedCogs) {
        if (price.compareTo(BigDecimal.ZERO) == 0) return;
        
        BigDecimal dividedResult = upliftedCogs.divide(price, 10, ROUND_HALF_UP);
        
        if (isBundle) {
            bdlMap.put(sku, dividedResult);
        }
        else if (productType.equals("HW")) {
            hwMap.put(sku, dividedResult);
        }
        else if (productType.equals("SaaS")) {
            saasMap.put(sku, dividedResult);
        }
        else if (productType.equals("IaaS")) {
            iaasMap.put(sku, dividedResult);
        }
        else if (productType.equals("SW")) {
            swMap.put(sku, dividedResult);
        }
        else if (productType.equals("SW-SUB")) {
            swsubMap.put(sku, dividedResult);
        }
    }
    
    // for Service
    public void addServiceUpliftedCogs(String sku, BigDecimal price, BigDecimal upliftedCogs, boolean isParent, boolean isStandalone, String parentProductType) {
        if (price.compareTo(BigDecimal.ZERO) == 0) return;
        
        BigDecimal dividedResult = upliftedCogs.divide(price, 10, ROUND_HALF_UP);
        
        if (isStandalone || parentProductType.equals("HW") || parentProductType.equals("SaaS") || parentProductType.equals("IaaS")) {
            _1_serviceMap.put(sku, dividedResult);
        }
        else if (isParent) {
            _12_serviceMap.put(sku, dividedResult);
        }
        else if (parentProductType.equals("SW")) {
            _066_serviceMap.put(sku, dividedResult);
        }
    }
  
