    public String[] findReferenceSku(String sku) {
        String tempSku = sku;
        boolean transformed = false;
        
        if(tempSku.contains("-G-") || tempSku.endsWith("-G")) {
            tempSku = tempSku.replace("-G", "");
            transformed = true;
        }
        if(tempSku.contains("-USG-") || tempSku.endsWith("-USG")) {
            tempSku = tempSku.replace("-USG", "");
            transformed = true;
        }
        if(tempSku.contains("-TAA-FGDUS-") || tempSku.endsWith("-TAA-FGDUS")) {
            tempSku = tempSku.replace("-TAA-FGDUS", "");
            transformed = true;
        }
        if(tempSku.contains("-TAA-") || tempSku.endsWith("-TAA")) {
            tempSku = tempSku.replace("-TAA", "");
            transformed = true;
        }
        if(tempSku.contains("-LENC-") || tempSku.endsWith("-LENC")) {
            tempSku = tempSku.replace("-LENC", "");
            transformed = true;
        }
        if(tempSku.contains("-NEBS-") || tempSku.endsWith("-NEBS")) {
            tempSku = tempSku.replace("-NEBS", "");
            transformed = true;
        }
        
        if(transformed) {
            return new String[]{"Y", tempSku};
        }
        else {
            return new String[]{"N", ""};
        }
    }

