    public void sortEntry(List<JSONObject> list) {
        Collections.sort(list, new Comparator<JSONObject>() {
            public int compare(JSONObject jo1, JSONObject jo2) {
                String unit1 = jo1.optString("unit");
                String sku1 = jo1.optString("sku");
                int seq1 = jo1.optInt("sequence");
                String unit2 = jo2.optString("unit");
                String sku2 = jo2.optString("sku");
                int seq2 = jo2.optInt("sequence");
                
                // sort sequence
                if (seq1 != seq2) return seq1 - seq2;
                
                // sort sku
                if (unit1.equals(unit2)) {
                    return sku1.compareTo(sku2);
                }
                
                // sort unit
                ArrayList<String> s1Section = new ArrayList<>();
                ArrayList<String> s2Section = new ArrayList<>();
                String[] dash;
                int s1SecLength, s2SecLength;

                dash = unit1.split("-");
                s1Section.add(dash[0]);
                //System.out.println("s1Split[0]:"+s1Section[0]);

                int k = 1;
                for (int i = 1; i < dash.length; i++) {
                    String[] part = dash[i].split("(?<=\\D)(?=\\d)|(?<=\\d)(?=\\D)");
                    s1Section.addAll(Arrays.asList(part));
                }
                s1SecLength = s1Section.size();
                /*System.out.println("s1SecLength:" + s1SecLength);
                for (int i = 0; i < s1Section.length && s1Section[i] != null; i++) {
                    System.out.println("s1Section:" + s1Section[i]);
                }*/

                dash = unit2.split("-");
                s2Section.add(dash[0]);
                //System.out.println("s2Split[0]:"+s2Section[0]);

                k = 1;
                for (int i = 1; i < dash.length; i++) {
                    String[] part = dash[i].split("(?<=\\D)(?=\\d)|(?<=\\d)(?=\\D)");
                    s2Section.addAll(Arrays.asList(part));
                }
                s2SecLength = s2Section.size();
                /*System.out.println("s2SecLength:" + s2SecLength);
                for (int i = 0; i < s2Section.length && s2Section[i] != null; i++) {
                    System.out.println("s2Section:" + s2Section[i]);
                }*/

                int length = (s1SecLength >= s2SecLength) ? s2SecLength : s1SecLength;
                //System.out.println("length:" + length);
                for (int i = 1; i < length; i++) {
                    if (s1Section.get(i) == null)
                        return -1;
                    else if (s2Section.get(i) == null)
                        return 1;
                    else if (!(s1Section.get(i).equals(s2Section.get(i)))) {
                        if (s1Section.get(i).matches("^-?\\d+$") && s2Section.get(i).matches("^-?\\d+$")) {
                            //System.out.println("Both Numeric:" + s1Section[i] + " " + s2Section[i]);
                            return Integer.parseInt(s1Section.get(i)) - Integer.parseInt(s2Section.get(i));
                        }
                        else {
                            //System.out.println("Not Both Numeric:" + s1Section[i] + " " + s2Section[i]);
                            if (s1Section.get(i) != null && s2Section.get(i) != null)
                                return s1Section.get(i).compareTo(s2Section.get(i));
                        }
                    }
                }
                if(s1SecLength > s2SecLength) {
                    //System.out.println(s1+" secLength > "+s2+" secLength");
                    return 1;
                }
                else if(s1SecLength < s2SecLength) {
                    //System.out.println(s1+" secLength < "+s2+" secLength");
                    return -1;
                }
                if (s1Section.get(0).matches("^-?\\d+$") && s2Section.get(0).matches("^-?\\d+$")) {
                    //System.out.println("Both Numeric:" + s1Section[0] + " " + s2Section[0]);
                    return Integer.parseInt(s1Section.get(0)) - Integer.parseInt(s2Section.get(0));
                }
                else {
                    //System.out.println("Not Both Numeric:" + s1Section[0] + " " + s2Section[0]);
                    return s1Section.get(0).compareTo(s2Section.get(0));
                }

            }
        });
    }
    
    public String getFactorString(String sku, String tab, String section, String productType, String upliftRange, String parentFactorStr) {
        if (!pricelistRegion.equals("EMEA") && !pricelistRegion.contains("APAC")) return "Region is not EMEA or APAC";
        //if (!currency.contains("EUR")) return "CurrencyNotEUR";
        
        if ((tab.equals("FortiGate") && section.equals("FortiGate - General"))
                || (tab.equals("FortiGate") && section.equals("FortiGate - Support for Additional FortiGate"))
                || (tab.equals("LENC") && section.equals("LENC - General"))) {
            if (parentFactorStr == null) {
                Integer firstInteger = getFirstInteger(sku);
                if (firstInteger == null) return "CannotFindInteger";
                if (firstInteger < 200) return "HW-Low";
                if (firstInteger >= 200 && firstInteger < 1000) return "HW-Mid";
                if (firstInteger >=1000) return "HW-High";
            }
            if (parentFactorStr.contains("Low")) return productType + "-Low";
            if (parentFactorStr.contains("Mid")) return productType + "-Mid";
            if (parentFactorStr.contains("High")) return productType + "-High";
            return "Service of FortiGate-General or LENC-General but no parent factor";
        }
        
        if (parentFactorStr == null) {   //Base Product
            if (sku.contains("Standalone")) return "Standalone";
            if (upliftRange.length() > 0) {
                if (!upliftRange.equals("Multiple")) {
                    return productType+"-"+upliftRange;
                }
                if (!productType.equals("Service")) {
                    Integer firstInteger = getFirstInteger(sku);
                    if (firstInteger == null) return "CannotFindInteger";
                    if (firstInteger < 200) return "HW-Low";
                    if (firstInteger >= 200 && firstInteger < 1000) return "HW-Mid";
                    if (firstInteger >=1000) return "HW-High";
                }
                if (tab.equals("PRMA") || tab.equals("PRMA Bundle Contracts")) {
                    if (sku.split("-").length >= 3) {
                        String productCode = sku.split("-")[2];
                        APIQuery aq = new APIQuery(apname, "/pricing", 20);
                        aq.setUpdateMode();
                        aq.addFilter(PARENT_PRODUCT_CODE, "=", productCode);
                        //aq.setFiltersStringV2(new String[]{TAB + "|" + 11 + "|" + "^(?!(prma|prma bundle constracts)$).*$"});
                        //aq.addFilter(TAB, operand, value)
                        APIResultsFull ar = aq.getAPIResultsFull();
                        for (APIEntry e : ar) {
                            String rTab = e.getFieldValue(TAB);
                            if (rTab.contains("PRMA")) continue;
                            
                            String rSection = e.getFieldValue(SECTION);
                            String rUpliftRange = getSectionUpliftRange(rTab, rSection);
                            if (rUpliftRange.length() > 0 && !rUpliftRange.equals("Multiple")) return productType+"-"+rUpliftRange;
                            
                            String rParentSku = e.getFieldValue(PARENT_SKU);
                            String rParentIdentifier = e.getFieldValue(PARENT_IDENTIFIER);
                            String rParentProductType = e.getFieldValue(PARENT_PRODUCT_TYPE);
                            String rParentFactorStr = getFactorString(rParentSku, rTab, rSection, rParentProductType, rUpliftRange, null);
                            if (rParentFactorStr.contains("Low")) return productType + "-Low";
                            if (rParentFactorStr.contains("Mid")) return productType + "-Mid";
                            if (rParentFactorStr.contains("High")) return productType + "-High";
                            //return rTab + " " + rSku + " no uplift";
                            
                            String rSku = e.getSubtableFieldValue(ADDON_SUBTABLE_KEY, 0, ""+SKU);
                            String rIdentifier = e.getFieldValue(IDENTIFIER);
                            String rProductType = e.getFieldValue(PRODUCT_TYPE);
                            String rFactorStr = getFactorString(rSku, rTab, rSection, rProductType, rUpliftRange, rParentFactorStr);
                            if (rFactorStr.contains("Low")) return productType + "-Low";
                            if (rFactorStr.contains("Mid")) return productType + "-Mid";
                            if (rFactorStr.contains("High")) return productType + "-High";
                        }
                        return "Can't find base product with this product code in any other tab";
                    }
                    else return "Can't find product code of "+sku;
                }
            }
            else {
                return getDefaultFactorStr(sku, tab, section, productType, parentFactorStr);
            }
        
        }
        else {
            if (upliftRange.length() > 0 && !upliftRange.equals("Multiple")) {
                return productType + "-" + upliftRange;
            }
            if (upliftRange.length() > 0 && upliftRange.equals("Multiple")) {
                if (parentFactorStr.endsWith("Low")) return productType + "-Low";
                if (parentFactorStr.endsWith("Mid")) return productType + "-Mid";
                if (parentFactorStr.endsWith("High")) return productType + "-High";
                return "";
            }
            if (parentFactorStr.contains("Standalone")) return productType + "-High";
            if (productType.equals("Service")) {
                if (parentFactorStr.contains("Low")) return "Service-Low";
                if (parentFactorStr.contains("Mid")) return "Service-Mid";
                if (parentFactorStr.contains("High")) return "Service-High";
                return "Parent No Uplift";
            }
            return getDefaultFactorStr(sku, tab, section, productType, parentFactorStr);
        }
        
        return "Cannot match any Rule";
    }
    
    public String getDefaultFactorStr(String sku, String tab, String section, String productType, String parentFactorStr) {
        if (productType.equals("Service")) {
            if (tab.equals("Adv-Services")) return "Service-No Uplift";
            /*if (parentFactorStr == null) {
                
            }
            else {
                if (parentFactorStr.contains("Low")) return "Service-Low";
                if (parentFactorStr.contains("Mid")) return "Service-Mid";
                if (parentFactorStr.contains("High")) return "Service-High";
            }*/
            return "Get No Default Factor";
        }
        else {
            if (tab.equals("Federal"))  return "NoUplift";
            if (tab.equals("FortiGate")) {
                if (section.equals("FortiGate - General")) {
                    Integer firstInteger = getFirstInteger(sku);
                    if (firstInteger == null) return "CannotFindInteger";
                    if (firstInteger < 200) return "HW-Low";
                    if (firstInteger >= 200 && firstInteger < 1000) return "HW-Mid";
                    if (firstInteger >=1000) return "HW-High";
                }
                if (section.equals("FortiGate - FortiGuard Premier Web Service")
                        || section.equals("FortiGate - FortiCarrier Upgrade")) return "HW-High";
                if (section.equals("FortiGate - FortiSMS")) return "HW-Low";
                return "HW-High";
            }
            if (tab.equals("LENC")) {
                if (section.equals("LENC - General")) {
                    Integer firstInteger = getFirstInteger(sku);
                    if (firstInteger == null) return "CannotFindInteger";
                    if (firstInteger < 200) return "HW-Low";
                    if (firstInteger >= 200 && firstInteger < 1000) return "HW-Mid";
                    if (firstInteger >= 1000) return "HW-High";
                }
                if (section.equals("LENC - Licence Key for FortiGate Low Encryption Models to Upgrade to FortiGate High Encryption Models")) return "SW-Low";
            }
            if (tab.equals("Other Products")) {
                if (section.equals("Other Products - FortiExtender") || section.equals("Other Products - FortiRecorder")
                        || section.equals("Other Products - FortiRecorder - 3rd Party Camera License")) return "HW-Low";
                if (productType.equals("HW")) return "HW-Low";
                if (productType.equals("SW")) return "SW-Low";
            }
            if (tab.equals("FortiSIEM")) {
                if (section.equals("FortiSIEM - Training and Professional Services")) return "SW-Low";
                return "HW-High";
            }
            if (tab.equals("FortiGate Chassis Platforms") || tab.equals("FortiGate VM") || tab.equals("VDOM")
                    || tab.equals("FortiSandbox") || tab.equals("ADN Products") || tab.equals("FortiDDoS")
                    || tab.equals("FortiWeb") || tab.equals("FortiMail") || tab.equals("FortiAnalyzer")
                    || tab.equals("FortiManager")) return "HW-High";
            if (tab.equals("FortiToken") || tab.equals("FortiSwitch") || tab.equals("Wireless Products")
                    || tab.equals("Accessories") || tab.equals("FortiVoice")) return "HW-Low";
            if (tab.equals("FortiClient") || tab.equals("FortiCloud")) return "SW-Low";
        }
        
        return "Cannot match any rule";
    }
    
    public String getFactor(String factorStr) {
        if (factorStr.equals("HW-Low")) return hwLow;
        if (factorStr.equals("HW-Mid")) return hwMid;
        if (factorStr.equals("HW-High")) return hwHigh;
        if (factorStr.equals("SW-Low")) return swLow;
        if (factorStr.equals("SW-Mid")) return swMid;
        if (factorStr.equals("SW-High")) return swHigh;
        if (factorStr.equals("Service-Low") || factorStr.equals("SaaS-Low") || factorStr.equals("IaaS-Low")) return serviceLow;
        if (factorStr.equals("Service-Mid") || factorStr.equals("SaaS-Mid") || factorStr.equals("IaaS-Mid")) return serviceMid;
        if (factorStr.equals("Service-High") || factorStr.equals("SaaS-High") || factorStr.equals("IaaS-High")) return serviceHigh;
        if (factorStr.equals("Service-No Uplift")) return serviceNoUplift;
        if (factorStr.equals("SW-SUB-Low")) return swSubLow;
        if (factorStr.equals("SW-SUB-Mid")) return swSubMid;
        if (factorStr.equals("SW-SUB-High")) return swSubHigh;
        return "1";
    }
    
    public Integer getFirstInteger(String s) {
        Pattern p = Pattern.compile("\\d+");
        Matcher m = p.matcher(s);
        if(m.find()) return Integer.valueOf(m.group());
        else return null;
    }
    
