    public Set<String> getTabSections(String tab, APIEntry tabEntry) {
        Set<String> result = new LinkedHashSet<>();
        Map<Integer, Integer> seqMap = new HashMap<>(); //sequence->subtableRowIndex
        List<Integer> seqList = new ArrayList<>();

        // get defined sections
        int subtableSize = tabEntry.getSubtableSize(TAB_SUBTABLE_KEY);
        for (int i = 0; i < subtableSize; i++) {
            boolean removal = tabEntry.getSubtableFieldValue(TAB_SUBTABLE_KEY, i, "" + SECTION_REMOVAL).equals("Y");
            String sequence = tabEntry.getSubtableFieldValue(TAB_SUBTABLE_KEY, i, "" + SECTION_SEQUENCE);
            if(removal) continue;
            if (sequence.equals("")) {
                seqMap.put(i, i);
                seqList.add(i);
            } 
            else {
                seqMap.put(Encoder.parseInt(sequence)*1000, i);
                seqList.add(Encoder.parseInt(sequence)*1000);
            }
        }
        Collections.sort(seqList);
        for (int seq : seqList) {
            int sectionRowIndex = seqMap.get(seq);
            String section = tabEntry.getSubtableFieldValue(TAB_SUBTABLE_KEY, sectionRowIndex, "" + TAB_SECTION_NAME);
            result.add(section);
        }

        //catch if not listed
        /*APIQuery aq = new APIQuery(apname, "/pricing", 1);
        aq.setUpdateMode();
        aq.addFilter(TAB, "=", tab);
        aq.addFetchDomains(SECTION);
        APIResultsFull ar = aq.getAPIResultsFull();
        for (APIEntry e : ar) {
            String section = e.getFieldValue(SECTION);
            result.add(section);
        }*/
        return result;
    }
    
    public String getSectionUpliftRange(String tab, String section) {
        APIQuery aq;
        if (useOldVersion) {
            aq = new APIQuery(apname, "/config", 7);
            aq.addFilter(TAB_ROOT_DOMAIN_ID, "=", pricelistName + "-" + tab);
        } else {
            aq = new APIQuery(apname, "/config", 3);
            aq.addFilter(TAB_ROOT_DOMAIN_ID, "=", tab);
        }
        aq.addFilter(TAB_SECTION_NAME, "=", section);
        aq.setUpdateMode();
        APIEntry e = aq.getAPIResult();
        if (e != null) {
            return e.getFieldValue(SECTION_UPLIFT_RANGE);
        }
        
        return "";
    }
    
