    public int findInsertStartRow(String tabName) {
        int startRow=0;
        if ("report".equals(wbName) && reportInsertionMarkRowNum!=null && reportInsertionMarkRowNum.containsKey(tabName)) {
            startRow = reportInsertionMarkRowNum.get(tabName);  //report wb
            reportInsertionMarkRowNum.put(tabName, startRow + 1);
        }
        else if(insertionMarkRowNum!=null && insertionMarkRowNum.containsKey(tabName)) {
            startRow = insertionMarkRowNum.get(tabName);  //pricelist wb
            insertionMarkRowNum.put(tabName, startRow + 1);
        }
        
        return startRow;
    }

    public Row shiftCreateRow(Sheet sheet) {
        //int rownum = findInsertionMark(sheet);
        int rownum = findInsertStartRow(sheet.getSheetName());
        //    return sheet.createRow(sheet.getLastRowNum()+1);
        //copyRow(wb, sheet, rownum, rownum + 1);
        return getRow(sheet, rownum);
    }

    public Row getRow(Sheet sheet, int rownum) {
        Row row = sheet.getRow(rownum);
        if (row == null) {
            row = sheet.createRow(rownum);
        }
        return row;
    }

