    public CellStyle addGrayBackground(CellStyle style) {
        CellStyle result = cloneStyle(style);
        String color = "#c0c0c0";
        result.setFillPattern(FillPatternType.SOLID_FOREGROUND);
        ((XSSFCellStyle) result).setFillForegroundColor(
                new XSSFColor(new byte[] { (byte) Integer.parseInt(color.substring(1, 3), 16),
                        (byte) Integer.parseInt(color.substring(3, 5), 16),
                        (byte) Integer.parseInt(color.substring(5, 7), 16) },new DefaultIndexedColorMap()));
        return result;
    }
    
    public CellStyle addLightGrayBackground(CellStyle style) {
        CellStyle result = cloneStyle(style);
        String color = "#d9d9d9";
        result.setFillPattern(FillPatternType.SOLID_FOREGROUND);
        ((XSSFCellStyle) result).setFillForegroundColor(
                new XSSFColor(new byte[] { (byte) Integer.parseInt(color.substring(1, 3), 16),
                        (byte) Integer.parseInt(color.substring(3, 5), 16),
                        (byte) Integer.parseInt(color.substring(5, 7), 16) },new DefaultIndexedColorMap()));
        return result;
    }

    @Deprecated
    private void copyRow(Workbook workbook, Sheet worksheet, int sourceRowNum, int destinationRowNum) {
        // Get the source / new row
        //System.out.println("sourceRowNum:"+sourceRowNum+", sheet:"+worksheet);
        Row newRow = worksheet.getRow(destinationRowNum);
        Row sourceRow = worksheet.getRow(sourceRowNum);
        //if(sourceRow==null) System.out.println("sourceRow="+sourceRow);

        // If the row exist in destination, push down all rows by 1 else create a new row
        if (newRow != null) {
            //System.out.println("destinationRowNum:"+destinationRowNum+", lastRowNum:"+worksheet.getLastRowNum()+", newRow.lastCellnum:"+newRow.getLastCellNum());
            //worksheet.shiftRows(destinationRowNum, worksheet.getLastRowNum(), 1);    // shiftRows caused to runtime exception: not implement yet
            newRow = worksheet.createRow(destinationRowNum);
        }
        else {
            newRow = worksheet.createRow(destinationRowNum);
        }

        // Loop through source columns to add to new row
        for (int i = 0; sourceRow != null && i < sourceRow.getLastCellNum(); i++) {
            // Grab a copy of the old/new cell
            Cell oldCell = sourceRow.getCell(i);
            Cell newCell = newRow.createCell(i);

            // If the old cell is null jump to next cell
            if (oldCell == null) {
                if (i > 0) {
                    newCell = null;
                    continue;
                }
                else {
                    oldCell = sourceRow.createCell(i);
                }
            }

            // Copy style from old cell and apply to new cell
            CellStyle newCellStyle = workbook.createCellStyle();
            newCellStyle.cloneStyleFrom(oldCell.getCellStyle());
            newCell.setCellStyle(newCellStyle);

            // If there is a cell comment, copy
            if (oldCell.getCellComment() != null) {
                newCell.setCellComment(oldCell.getCellComment());
            }

            // If there is a cell hyperlink, copy
            if (oldCell.getHyperlink() != null) {
                newCell.setHyperlink(oldCell.getHyperlink());
            }

            // Set the cell data type
            newCell.setCellType(oldCell.getCellType());

            // Set the cell data value
            switch (oldCell.getCellType()) {
            case BLANK:
                newCell.setCellValue(oldCell.getStringCellValue());
                break;
            case BOOLEAN:
                newCell.setCellValue(oldCell.getBooleanCellValue());
                break;
            case ERROR:
                newCell.setCellErrorValue(oldCell.getErrorCellValue());
                break;
            case FORMULA:
                newCell.setCellFormula(oldCell.getCellFormula());
                break;
            case NUMERIC:
                newCell.setCellValue(oldCell.getNumericCellValue());
                break;
            case STRING:
                newCell.setCellValue(oldCell.getRichStringCellValue());
                break;
            }
        }

        // If there are are any merged regions in the source row, copy to new row
        for (int i = 0; i < worksheet.getNumMergedRegions(); i++) {
            CellRangeAddress cellRangeAddress = worksheet.getMergedRegion(i);
            if (sourceRow != null && cellRangeAddress.getFirstRow() == sourceRow.getRowNum()) {
                CellRangeAddress newCellRangeAddress = new CellRangeAddress(newRow.getRowNum(),
                        (newRow.getRowNum() + (cellRangeAddress.getLastRow() - cellRangeAddress.getFirstRow())),
                        cellRangeAddress.getFirstColumn(), cellRangeAddress.getLastColumn());
                worksheet.addMergedRegion(newCellRangeAddress);
            }
        }
    }
    
    public double rateExchange(String p, String f) {
        BigDecimal price = Encoder.parseBigDecimal(p, BigDecimal.ZERO);
        BigDecimal factor = Encoder.parseBigDecimal(f, BigDecimal.ONE);
        return price.multiply(factor).setScale(2, ROUND_HALF_UP).doubleValue();
    }
    
