  public void _jspService(final javax.servlet.http.HttpServletRequest request, final javax.servlet.http.HttpServletResponse response)
      throws java.io.IOException, javax.servlet.ServletException {

    final java.lang.String _jspx_method = request.getMethod();
    if (!"GET".equals(_jspx_method) && !"POST".equals(_jspx_method) && !"HEAD".equals(_jspx_method) && !javax.servlet.DispatcherType.ERROR.equals(request.getDispatcherType())) {
      response.sendError(HttpServletResponse.SC_METHOD_NOT_ALLOWED, "JSPs only permit GET POST or HEAD");
      return;
    }

    final javax.servlet.jsp.PageContext pageContext;
    javax.servlet.http.HttpSession session = null;
    final javax.servlet.ServletContext application;
    final javax.servlet.ServletConfig config;
    javax.servlet.jsp.JspWriter out = null;
    final java.lang.Object page = this;
    javax.servlet.jsp.JspWriter _jspx_out = null;
    javax.servlet.jsp.PageContext _jspx_page_context = null;


    try {
      response.setContentType("text/html; charset=UTF-8");
      pageContext = _jspxFactory.getPageContext(this, request, response,
      			null, true, 8192, true);
      _jspx_page_context = pageContext;
      application = pageContext.getServletContext();
      config = pageContext.getServletConfig();
      session = pageContext.getSession();
      out = pageContext.getOut();
      _jspx_out = out;


    final SimpleDateFormat sdf = new SimpleDateFormat("yyyy/MM/dd hh:mm:ss");
    //System.out.println("pricelist start: " + sdf.format(new Date()));
    new Log("log/FNTNpricelist.log").info("pricelist start: " + sdf.format(new Date()));
    apname = request.getParameter("a");
    final int rootNodeId = Encoder.parseInt(request.getParameter("n"), Const.NONODE);
    final NUIForm form = AppManager.getFormPage(apname, "/pricing", 4);
    final String env = "FNTN".equals(apname) ? "production" : "testing";
    
    // Get template name that uploaded by FNTN
    String templateName = "";
    APIQuery pricelistQuery = new APIQuery(apname, "/pricing", 4);
    pricelistQuery.setUpdateMode();
    APIEntry pricelistEntry = pricelistQuery.getAPIEntry(rootNodeId);
    
    if (pricelistEntry.getFieldValue(1002889).equals("Y")) {
        out.println("<script>alert('The price list has been locked.');window.close();</script>");
        return;
    }
    pricelistRegion = pricelistEntry.getFieldValue(1002824);
    pricelistName = pricelistEntry.getFieldValue(PRICE_LIST_NAME);
    if (!pricelistRegion.equals("Americas") && !pricelistRegion.equals("Japan")
            && !pricelistRegion.equals("EMEA") && !pricelistRegion.equals("APAC")) {
        out.println("<script>alert('"+pricelistRegion+" is not the right region.');window.close();</script>");
        return;
    }
    if (pricelistRegion.equals("EMEA") || pricelistRegion.equals("APAC")) {
        currency = pricelistEntry.getFieldValue(CURRENCY);
    }
    else {
        currency = "USD";
    }
    isDemoPricelist = "Y".equals(pricelistEntry.getFieldValue(DEMO_MODE));
    hwLow = pricelistEntry.getFieldValue(HW_LOW_FACTOR);
    hwMid = pricelistEntry.getFieldValue(HW_MID_FACTOR);
    hwHigh = pricelistEntry.getFieldValue(HW_HIGH_FACTOR);
    swLow = pricelistEntry.getFieldValue(SW_LOW_FACTOR);
    swMid = pricelistEntry.getFieldValue(SW_MID_FACTOR);
    swHigh = pricelistEntry.getFieldValue(SW_HIGH_FACTOR);
    serviceLow = pricelistEntry.getFieldValue(SERVICE_LOW);
    serviceMid = pricelistEntry.getFieldValue(SERVICE_MID);
    serviceHigh = pricelistEntry.getFieldValue(SERVICE_HIGH);
    serviceNoUplift = pricelistEntry.getFieldValue(SERVICE_NO_UPLIFT);
    swSubLow = pricelistEntry.getFieldValue(SW_SUB_LOW_FACTOR);
    swSubMid = pricelistEntry.getFieldValue(SW_SUB_MID_FACTOR);
    swSubHigh = pricelistEntry.getFieldValue(SW_SUB_HIGH_FACTOR);
    
    useOldVersion = false;
    APIQuery vbpQuery = new APIQuery(apname, "/pricing", 7);
    vbpQuery.setUpdateMode();
    vbpQuery.addFilter(VERSIONED_PARENT_VERSION_ID, "=", pricelistName);
    APIEntry vbpEntry = vbpQuery.getAPIResult();
    if (vbpEntry != null) useOldVersion = true;
    
    APIQuery templateQuery = new APIQuery(apname, "/config", 2);
    templateQuery.setUpdateMode();
    templateQuery.addFilter(1002591, "=", pricelistRegion);
    templateQuery.addFilter(1002825, "=", "Active");
    if (isDemoPricelist) {
        templateQuery.addFilter(1003217, "=", "Y");
    }
    
    APIResultsFull templateResults = templateQuery.getAPIResultsFull();
    for (APIEntry templateEntry : templateResults) {
        // we can't filter [empty value or 'N'] by regex
        if (!isDemoPricelist && "Y".equals(templateEntry.getFieldValue(1003217))) {
            continue;
        }
        templateName = templateEntry.getFieldValue(1002590);
        if(!templateName.equals(""))
            break;
    }
    
    if (templateName.equals("")) {
        out.println("<script>alert('There is no template for region "+pricelistRegion+"');window.close();</script>");
        return;
    }
    
    //make sure only one executed for one session
    long now = new Date().getTime();
    String startedTimeLong = SystemCache.getInstance().get("ACTION_BUTTON_START" + apname);
    if(startedTimeLong != null && request.getParameter("force") == null){
        long startedTime = Long.parseLong(startedTimeLong);
        long diff = (now-startedTime)/(1000*60);  //minutes
        if (diff > (long)60) {
            // force to restart if started time is greater than 1 hours (may caused by exception and stopped long ago)
            SystemCache.getInstance().put("ACTION_BUTTON_START" + apname, "" + new Date().getTime());
        }
        else {
            out.println("<script>alert('You already have an action button executing " + diff + " minutes ago, please wait for it to finish.');window.close();</script>");
            return;
        }
    }
    else{
        SystemCache.getInstance().put("ACTION_BUTTON_START" + apname, "" + new Date().getTime());
    }
    
    
    //get custom parameters
    APIQuery custParamQuery = new APIQuery(apname, "/config", 8);
    custParamQuery.setUpdateMode();
    APIEntry custParamEntry = custParamQuery.getAPIResult();
    usgUpliftFactor = Encoder.parseBigDecimal(custParamEntry.getFieldValue(1003439), BigDecimal.ONE);
    upliftCogsMultiplier = Encoder.parseBigDecimal(custParamEntry.getFieldValue(1003462), BigDecimal.ZERO);
    
    
    String password = Encoder.genPassword(10);
    int fileDomain, reportDomain;
    if (pricelistRegion.equals("EMEA") && (currency.equals("EUR ver1") || currency.equals("EMEA (EURO)"))) {
        fileDomain = 1003175;
        reportDomain = 1003188;
    }
    else if (pricelistRegion.equals("EMEA") && (currency.equals("EUR ver2") || currency.equals("EMEA (MEA)"))) {
        fileDomain = 1003176;
        reportDomain = 1003190;
    }
    else if (pricelistRegion.equals("EMEA") && (currency.equals("RUA ver") || currency.equals("EMEA (RUA)"))) {
        fileDomain = 1003180;
        reportDomain = 1003191;
    }
    else if (pricelistRegion.equals("EMEA") && currency.equals("EMEA (GBP)")) {
        fileDomain = 1003218;
        reportDomain = 1003219;
    }
    else if (pricelistRegion.equals("EMEA") && currency.equals("EMEA (DKK)")) {
        fileDomain = 1003424;
        reportDomain = 1003429;
    }
    else if (pricelistRegion.equals("EMEA") && currency.equals("EMEA (NOK)")) {
        fileDomain = 1003425;
        reportDomain = 1003430;
    }
    else if (pricelistRegion.equals("EMEA") && currency.equals("EMEA (SEK)")) {
        fileDomain = 1003426;
        reportDomain = 1003431;
    }
    else if (pricelistRegion.equals("EMEA") && currency.equals("EMEA (PLN)")) {
        fileDomain = 1003427;
        reportDomain = 1003432;
    }
    else if (pricelistRegion.equals("EMEA") && currency.equals("EMEA (CHF)")) {
        fileDomain = 1003428;
        reportDomain = 1003434;
    }
    else if (pricelistRegion.equals("EMEA") && currency.equals("EMEA (ISR)")) {
        fileDomain = 1003433;
        reportDomain = 1003435;
    }
    else if (pricelistRegion.equals("APAC") && (currency.equals("APAC ver2") || currency.equals("APAC (SEAHK)"))) {
        fileDomain = 1003177;
        reportDomain = 1003187;
    }
    else if (pricelistRegion.equals("APAC") && (currency.equals("INR ver") || currency.equals("APAC (INDIA)"))) {
        fileDomain = 1003179;
        reportDomain = 1003189;
    }
    else {
        fileDomain = 1002579;
        reportDomain = 1003186;
    }
    
    String filePrefix = password + "@" + pricelistName.replaceAll("Price Lists?", "");
    
    AbstractExportConfig aec = new AbstractExportConfig(form, rootNodeId, fileDomain, 1002549, 1002547, 1002548,
            filePrefix+"PriceList.xlsx", "cust/data/"+apname+"/upload/"+templateName) {
        @Override
        public void processWorkbook(Workbook workbook, Workbook workbook2) {

            // create styles
            wb = workbook;
            report_wb = workbook2;
            
            textFont = styleTextFont(wb, textFont);
            report_textFont = styleTextFont(report_wb, report_textFont);
            boldFont = styleBoldFont(wb, boldFont);
            titleFont = styleTitleFont(wb, titleFont);
            sectionFont = styleSectionFont(wb, sectionFont);
            
            sectionTitleFont = styleSectionTitleFont(wb, sectionTitleFont);
            
            report_sectionTitleFont = styleSectionTitleFont(report_wb, report_sectionTitleFont);
            
            headerCell = styleHeaderCell(wb, boldFont, headerCell);
            
            titleCell = styleTitleCell(wb, titleFont, titleCell);
            
            sectionTitleCell = styleSectionTitleCell(wb, sectionTitleFont, sectionTitleCell);
            
            blankCell = styleBlankCell(wb, textFont, blankCell);
            
            report_blankCell = styleBlankCell(report_wb, report_textFont, report_blankCell);

            dataformat = wb.createDataFormat();

            textData = styleTextData(wb, textFont, textData);
            textDataBottomBorder = addBottomBorder(textData);
            textData_grayBackground = addGrayBackground(textData);
            textData_grayBackground_bottomBorder = addGrayBackground(textDataBottomBorder);

            numberData = styleNumberData(wb, textFont, numberData, dataformat, pricelistRegion, currency, 0);
            numberData2Digits = styleNumberData(wb, textFont, numberData, dataformat, pricelistRegion, currency, 2);
            
            numberDataRightBorder = addRightBorder(numberData);
            numberDataBottomRightBorder = addBottomBorder(numberDataRightBorder);
            numberData_grayBackground_rightBorder = addGrayBackground(numberDataRightBorder);
            numberData_grayBackground_bottomRightBorder = addGrayBackground(numberDataBottomRightBorder);
            
            numberDataUSD = styleNumberDataUSD(wb, textFont, numberDataUSD, dataformat, pricelistRegion);
            numberDataUSDRightBorder = addRightBorder(numberDataUSD);

            centerTextData = styleCenterTextData(wb, textFont, centerTextData, dataformat);
            centerTextDataBottomBorder = addBottomBorder(centerTextData);
            centerTextData_grayBackground = addGrayBackground(centerTextData);
            centerTextData_grayBackground_bottomBorder = addGrayBackground(centerTextDataBottomBorder);

            boldDataCell = styleBoldDataCell(wb, boldFont, boldDataCell);
            boldDataCellBottomBorder = addBottomBorder(boldDataCell);
            boldDataCell_grayBackground = addGrayBackground(boldDataCell);
            boldDataCell_grayBackground_bottomBorder = addGrayBackground(boldDataCellBottomBorder);
            
            boldDataCell_lightGrayBackground = addLightGrayBackground(boldDataCell);
            
            topBorderCell = addTopBorder(blankCell);
            bottomBorderCell = addBottomBorder(blankCell);
            leftBorderCell = addLeftBorder(blankCell);
            
            topRightBorderCell = addTopBorder(addRightBorder(blankCell));
            
            report_backgroundCell = styleBackgroundCell(report_wb, report_sectionTitleFont, report_backgroundCell);
            

            Map<String, DataSet> mapDataSetNew = new LinkedHashMap<>();  //Map(sku, DataSet)
            Map<String, DataSet> mapDataSetOld = new LinkedHashMap<>();
            Map<String, Report> reportMap = new HashMap<>();  //Map(tabName, report)
            
            APIQuery aq;
            APIResultsFull ar;
            if (useOldVersion) {
                basePath = "/pricing";
                addonPath = "/versioned-addon";
            }
            else {
                basePath = "/pricing";
                addonPath = "/pricing";
            }
            if (pricelistRegion.equals("Japan")) {
                if (useOldVersion) {
                    baseSheetIndex = 7;
                    addonSheetIndex = 2;
                }
                else {
                    baseSheetIndex = 19;
                    addonSheetIndex = 15;
                }
            }
            else if (pricelistRegion.equals("EMEA")) {
                if (useOldVersion) {
                    baseSheetIndex = 7;
                    addonSheetIndex = 3;
                }
                else {
                    baseSheetIndex = 20;
                    addonSheetIndex = 16;
                }
            }
            else if (pricelistRegion.equals("APAC")) {
                if (useOldVersion) {
                    baseSheetIndex = 7;
                    addonSheetIndex = 4;
                }
                else {
                    baseSheetIndex = 21;
                    addonSheetIndex = 17;
                }
            }
            else {
                if (useOldVersion) {
                    baseSheetIndex = 7;
                    addonSheetIndex = 1;
                }
                else {
                    baseSheetIndex = 18;
                    addonSheetIndex = 11;
                }
            }
            
            List<String> tabList = new ArrayList<>();
            Map<String, APIEntry> tabMap = new HashMap<>();
            
            if (isDemoPricelist) {
                // DEMO Pricelists only need to output DataSet and Change tab, and don't need to calculate Uplifted COGS
                Sheet dataSetSheet = null;
                try {
                    dataSetSheet = wb.getSheet("DataSet");
                } catch (Exception e) {
                }
                
                List<String> skuList = new ArrayList<>();
                Map<String, APIEntry> entryMap = new HashMap<>();
                
                aq = new APIQuery(apname, basePath, baseSheetIndex);
                aq.setUpdateMode();
                aq.addFilter(FOR_DEMO_PRICE_LIST, "=", "Y");
                
                ar = aq.getAPIResultsFull();
                for (APIEntry e : ar) {
                    String sku = e.getFieldValue(PARENT_SKU);
                    skuList.add(sku);
                    entryMap.put(sku, e);
                }

                Collections.sort(skuList);
                
                for (String sku : skuList) {
                    APIEntry e = entryMap.get(sku);
                    boolean ifWriteToExcel = true;
                    
                    determineProductTypeOfEntry(e);
                    
                    if(dataSetSheet != null) {
                        outputDataSetItem(dataSetSheet, e, mapDataSetNew, ifWriteToExcel);
                    }
                }
            }
            else {
                // standard percentage map for price report, only need to read once
                Map<String, BigDecimal> standardPercentage = new HashMap<>(); //skuSuffix -> standard percentage
                standardPercentage = readStandardPercentage(apname);
                        
                if (useOldVersion) {
                    aq = new APIQuery(apname, "/config", 6);
                    aq.addFilter(1003232, "=", pricelistName);
                }
                else {
                    aq = new APIQuery(apname, "/config", 1);
                }
                aq.setUpdateMode();
                APIResultsFull tabResults = aq.getAPIResultsFull();
    
                //System.out.println("start outputBaseHardware and outputDataSet:" + sdf.format(new Date()));
                new Log("log/FNTNpricelist.log").info("start outputBaseHardware and outputDataSet:" + sdf.format(new Date()));
                
                // sort items then skus in Changes tab would sorted by tab(location)
                // if sort skus at outputChanges(), then skus in a tab might disorder because sorting skus instead of sorting items
                for (APIEntry tabEntry : tabResults) {
                    // process each tab
                    String tabName = tabEntry.getFieldValue(TAB_TAB_NAME);
                    if (tabName == null)
                        continue;
                    tabList.add(tabName);
                    tabMap.put(tabName, tabEntry);
                }
                Collections.sort(tabList);
                
                // each base hardware in a section
                for (String tabName : tabList) {
                    
                    // process each tab
                    APIEntry tabEntry = tabMap.get(tabName);
                    if (tabName == null)
                        continue;
                    Sheet sheet = null;
                    try {
                        sheet = wb.getSheet(tabName);
                    } catch (Exception e) {
                    }
                    if (sheet == null) {
                        //System.out.println("Cannot find tab:" + tabName);
                        continue;
                    }
                    // Sheet reportSheet = null;
                    // try {
                    //     reportSheet = report_wb.getSheet(tabName);
                    // } catch (Exception e) {
                    // }
                    // if (reportSheet == null) {
                    //     System.out.println("Cannot find tab:" + tabName);
                    //     continue;
                    // }
                    Sheet dataSetSheet = null;
                    try {
                        dataSetSheet = wb.getSheet("DataSet");
                    } catch (Exception e) {
                    }
                    //System.out.println("tabName:"+tabName);
                    
                    Report report = new Report();
                    reportMap.put(tabName, report);
                    report.setStandardPercentage(standardPercentage);
                    
                    // process each tab sections
                    Set<String> sections = getTabSections(tabName, tabEntry);
                    for (String section : sections) {
                        // APIQuery.addFilter(domainId, "=", "") won't work, it filters out all entries
                        if ("".equals(section)) continue;
                        // print section header
                        if (section != null && section.length() > 0) {
                            //System.out.println("section:"+section);
                            Row row = shiftCreateRow(sheet);
                            row.setHeightInPoints((float)30);
                            int cellCount = 0;
                            Cell cell = row.createCell(cellCount);
                            int colspan = 10;
                            if (pricelistRegion.equals("Japan")) {
                                colspan = 11;
                            }
                                
                            sheet.addMergedRegion(new CellRangeAddress(
                                    cell.getRowIndex(), //first row (0-based)
                                    cell.getRowIndex(), //last row  (0-based)
                                    cell.getColumnIndex(), //first column (0-based)
                                    cell.getColumnIndex()+colspan  //last column  (0-based)
                            ));
                            CellStyle style = cloneStyle(sectionTitleCell);
                            //style.setFont(sectionFont);
                            cell.setCellStyle(style);
                            cell.setCellValue(section);
                            
                            for (int j = 1; j <= colspan; j++) {
                                cell = row.createCell(++cellCount);
                                if (j == colspan) {
                                    cell.setCellStyle(topRightBorderCell);
                                }
                                else {
                                    cell.setCellStyle(topBorderCell);
                                }
                                cell.setCellValue("");
                            }
                            
                        }
    
                        Map<String, APIEntry> entryMap = new HashMap<>();
                        List<JSONObject> dataList = new ArrayList<>();
                        
                        aq = new APIQuery(apname, basePath, baseSheetIndex);
                        aq.setUpdateMode();
                        aq.addFilter(TAB, "=", tabName);
                        aq.addFilter(SECTION, "=", section);
                        if (useOldVersion) {
                            aq.addFilter(VERSIONED_PARENT_VERSION_ID, "=", pricelistName);
                            aq.addFilter(VERSIONED_PARENT_REGION, "=", pricelistRegion);
                        }
                        
                        ar = aq.getAPIResultsFull();
                        for (APIEntry e : ar) {
                            // we can't filter [empty value or 'N'] by regex
                            String forDemoPriceList = e.getFieldValue(FOR_DEMO_PRICE_LIST);
                            if (!isDemoPricelist && "Y".equals(forDemoPriceList)) continue;
                            
                            String unit = e.getFieldValue(PARENT_UNIT);
                            String sku = e.getFieldValue(PARENT_SKU);
                            int sequence = Encoder.parseInt(e.getFieldValue(PARENT_SEQUENCE), -1);
                            JSONObject jo = new JSONObject();  //add [unit, sku, sequence] to a JSONObject for sorting
                            try {
                                jo.put("unit", unit);
                                jo.put("sku", sku);
                                jo.put("sequence", sequence);
                            } catch (Exception ig) {}
                            
                            dataList.add(jo);
    
                        
                            // 現在除了 unit 排序和 sku 排序之外還增加指定 sequence 排序，因此不能再用下面這個方法
                            // 改成每筆 entry 都建成一個 JSONObject 丟進 dataList，dataList 整個拿去排序
                            //   put every unit in map and arraylist for sorting
                            //   different skus may have same unit
                            
                            entryMap.put(sku, e);
                        }
                        
                        /*System.out.println("=====Print Out BaseHardware ArrayList=====");
                        for (JSONObject jo : dataList) {
                            System.out.println("unit:"+jo.optString("unit")+", sku:"+jo.optString("sku")+", sequence:"+jo.optString("sequence"));
                        }
                        System.out.println("=====End Of Print Out BaseHardware ArrayList=====");*/
    
                        sortEntry(dataList);
    
                        /*System.out.println("=====Print Out Sorted ArrayList=====");
                        for (JSONObject jo : dataList) {
                            System.out.println("unit:"+jo.optString("unit")+", sku:"+jo.optString("sku")+", sequence:"+jo.optString("sequence"));
                        }
                        System.out.println("=====End Of Print Out Sorted ArrayList=====");*/
    
                        for (Iterator<JSONObject> iter1 = dataList.iterator(); iter1.hasNext();) {
                            JSONObject jo = iter1.next();
                            String sku = jo.optString("sku");
                            
                            APIEntry e = entryMap.get(sku);
                            boolean ifWriteToExcel = true;
                            String upliftRange = getSectionUpliftRange(tabName, section);
                            e.setFieldValue(UPLIFT_RANGE, upliftRange);
                            
                            determineProductTypeOfEntry(e);
                            
                            outputBaseHardware(sheet, e, !iter1.hasNext());
                            ////autoSizeColumn will result in corrupt output in poi 3.1.17
                            //sheet.autoSizeColumn(1);
                            
                            if(dataSetSheet != null) {
                                
                                // We don't check reference SKU here anymore
                                // 可能因為 base product sku 不再使用或是 addon 被移動等因素，用 base product sku 可能找不到 reference sku
                                // 要用 addon sku 找 addon reference sku 再去找 base product reference sku
                                // 所以這個步驟已經移到 determineSku() 做，展開 addon sku 的時候再去找
                                
                                outputDataSetItem(dataSetSheet, e, mapDataSetNew, ifWriteToExcel);
                            }
                        }
                        
                        inOneOffTable = false;
                    }
                    
                    // wbName = "report";
                    // outputReport(reportSheet, tabName, report);
                    // wbName = "";
                }
            }
            //System.out.println("finish outputBaseHardware and outputDataSet: " + sdf.format(new Date()));
            new Log("log/FNTNpricelist.log").info("finish outputBaseHardware and outputDataSet: " + sdf.format(new Date()));

            aq = new APIQuery(apname, "/pricing", 4);
            aq.setUpdateMode();
            APIEntry ae = aq.getAPIEntry(rootNodeId);
            String preVersionId = ae.getFieldValue(PRE_PRICE_LIST_ID);
            String effectiveDate = ae.getFieldValue(EFFECTIVE_DATE);
            try {
                Date effDate = ymdFormat.parse(effectiveDate);
                effectiveDate = mdyFormat.format(effDate);
            } catch (Exception err) {}

            // Ouput change tab
            aq = new APIQuery(apname, "/pricing", 7);
            aq.setUpdateMode();
            aq.addFilter(VERSIONED_PARENT_VERSION_ID, "=", preVersionId);
            aq.addFilter(VERSIONED_PARENT_REGION, "=", pricelistRegion);
            if (isDemoPricelist) {
                aq.addFilter(VERSIONED_FOR_DEMO_PRICE_LIST, "=", "Y");
            }
            Sheet sheet = null;
            try {
                sheet = wb.getSheet("Changes");
            } catch (Exception e) {
                ExceptionManager.getInstance().processException(e);
            }
            if (sheet != null) {
                if (!preVersionId.equals("")) {
                    boolean ifWriteToExcel = false;
                    Map<String, List<APIEntry>> vTabMap = new HashMap<>();  // tab map to list of entry
                    List<String> vTabList = new ArrayList<>();
                    
                    ar = aq.getAPIResultsFull();
                    for (APIEntry e : ar) {
                        // we can't filter empty value or 'N' by regex
                        String forDemoPriceList = e.getFieldValue(VERSIONED_FOR_DEMO_PRICE_LIST);
                        if (!isDemoPricelist && "Y".equals(forDemoPriceList)) continue;
                        
                        String vTab = e.getFieldValue(VERSIONED_TAB);
                       
                        determineProductTypeOfEntry(e);
                        
                        // put tab name and entry to map for sorting
                        if (vTabList.indexOf(vTab) < 0) {
                            vTabList.add(vTab);
                        }
                        List<APIEntry> entryList = vTabMap.get(vTab);
                        if (entryList == null) {
                            entryList = new ArrayList<>();
                            entryList.add(e);
                            vTabMap.put(vTab, entryList);
                        }
                        else {
                            entryList.add(e);
                        }
                    }
                    
                    // sort skus by tab name in Changes tab 
                    Collections.sort(vTabList);
                    for (String vTab : vTabList) {
                        List<APIEntry> vEntryList = vTabMap.get(vTab);
                        for (APIEntry e : vEntryList) {
                            outputDataSetItem(sheet, e, mapDataSetOld, ifWriteToExcel);
                        }
                    }
                }
                
                outputChanges(sheet, effectiveDate, mapDataSetNew, mapDataSetOld, reportMap);
            }
            //System.out.println("finish outputChange: " + sdf.format(new Date()));
            new Log("log/FNTNpricelist.log").info("finish outputChange: " + sdf.format(new Date()));
            
            
            // Output report
            if (!isDemoPricelist) {
                for (String tabName : tabList) {
                    if (tabName == null)
                        continue;
                    Sheet reportSheet = null;
                    try {
                        reportSheet = report_wb.getSheet(tabName);
                    } catch (Exception e) {
                    }
                    if (reportSheet == null) {
                        //System.out.println("Cannot find tab:" + tabName);
                        continue;
                    }
                    
                    Report report = reportMap.get(tabName);
                    wbName = "report";
                    outputReport(reportSheet, tabName, report);
                    wbName = "";
                }
                new Log("log/FNTNpricelist.log").info("finish outputReport: " + sdf.format(new Date()));
            }

        }
        public boolean ifSXSSF(){
            return true;
        }
    };

    // Open template by XSSFWorkbook first to find insertion mark
    XSSFWorkbook template = null;
    InputStream fs = null;
    try {
        fs = new FileInputStream("cust/data/"+apname+"/upload/"+templateName);
        template = new XSSFWorkbook(fs);
    } catch (IOException e) {
        ExceptionManager.getInstance().processException(e);
        return;
    } finally {
        fs.close();
        template.close();
    }

    // set field ids of Tab sheet here, we'll use them later
    setTabFieldId();
    
    APIQuery aq;
    if (useOldVersion) {
        aq = new APIQuery(apname, "/config", 6);
        aq.addFilter(1003232, "=", pricelistName);
    } else {
        aq = new APIQuery(apname, "/config", 1);
    }
    aq.setUpdateMode();
    APIResultsFull tabResults = aq.getAPIResultsFull();
    
    for (APIEntry tabEntry : tabResults) {
        String tabName = tabEntry.getFieldValue(TAB_TAB_NAME);
        if (tabName == null)
            continue;
        Sheet sheet = null;
        try {
            sheet = template.getSheet(tabName);
        } catch (Exception e) {
        }
        if (sheet == null) {
            //System.out.println("Cannot find tab:" + tabName);
            continue;
        }

        //System.out.println("tabName:"+tabName);
        int rowNum = findInsertionMark(sheet);
        //System.out.println("rowNum:"+rowNum);
        insertionMarkRowNum.put(tabName, rowNum+2);
        reportInsertionMarkRowNum.put(tabName, rowNum+2);
    }
    
    String tabName = "DataSet";
    Sheet sheet = null;
    try {
        sheet = template.getSheet(tabName);
    } catch (Exception e) {
    }
    if (sheet != null) {
        //System.out.println("tabName:"+tabName);
        int rowNum = findInsertionMark(sheet);
        //System.out.println("rowNum:"+rowNum);
        insertionMarkRowNum.put(tabName, rowNum);
    }
    
    tabName = "Changes";
    sheet = null;
    try {
        sheet = template.getSheet(tabName);
    } catch (Exception e) {
    }
    if (sheet != null) {
        //System.out.println("tabName:"+tabName);
        int rowNum = findInsertionMark(sheet);
        //System.out.println("rowNum:"+rowNum);
        insertionMarkRowNum.put(tabName, rowNum);
    }
    
    String jsonString, verJsonString;
    if (pricelistRegion.equals("Japan")) {
        if (useOldVersion) jsonString = readFile("web/cust/fntn/"+env+"/Ver_Japan.json");
        else jsonString = readFile("web/cust/fntn/"+env+"/Japan.json");
        verJsonString = readFile("web/cust/fntn/"+env+"/Ver_Japan.json");
    }
    else if (pricelistRegion.equals("EMEA")) {
        if (useOldVersion) jsonString = readFile("web/cust/fntn/"+env+"/Ver_EMEA.json");
        else jsonString = readFile("web/cust/fntn/"+env+"/EMEA.json");
        verJsonString = readFile("web/cust/fntn/"+env+"/Ver_EMEA.json");
    }
    else if (pricelistRegion.equals("APAC")) {
        if (useOldVersion) jsonString = readFile("web/cust/fntn/"+env+"/Ver_APAC.json");
        else jsonString = readFile("web/cust/fntn/"+env+"/APAC.json");
        verJsonString = readFile("web/cust/fntn/"+env+"/Ver_APAC.json");
    }
    else {
        if (useOldVersion) jsonString = readFile("web/cust/fntn/"+env+"/Ver_Americas.json");
        else jsonString = readFile("web/cust/fntn/"+env+"/Americas.json");
        verJsonString = readFile("web/cust/fntn/"+env+"/Ver_Americas.json");
    }
    fieldId = new JSONObject(jsonString);
    setFieldId(fieldId);
    verFieldId = new JSONObject(verJsonString);
    setVerFieldId(verFieldId);
    
    request.setAttribute("EXPORT_CONFIG", aec);
    request.setAttribute("REPORT_FILE_NAME", filePrefix+"Report.xlsx");
    request.setAttribute("REPORT_DOMAIN", reportDomain);

      org.apache.jasper.runtime.JspRuntimeLibrary.include(request, response, "exportExcel.jsp", out, false);

    SystemCache.getInstance().remove("ACTION_BUTTON_START"+apname);

    } catch (java.lang.Throwable t) {
      if (!(t instanceof javax.servlet.jsp.SkipPageException)){
        out = _jspx_out;
        if (out != null && out.getBufferSize() != 0)
          try {
            if (response.isCommitted()) {
              out.flush();
            } else {
              out.clearBuffer();
            }
          } catch (java.io.IOException e) {}
        if (_jspx_page_context != null) _jspx_page_context.handlePageException(t);
        else throw new ServletException(t);
      }
    } finally {
      _jspxFactory.releasePageContext(_jspx_page_context);
    }
  }
